import os
from flask import Flask, jsonify, request, send_file
from werkzeug.utils import safe_join
import mimetypes

app = Flask(__name__)

# Base directory for user files - should be configured appropriately
BASE_UPLOAD_DIR = os.path.abspath('./user_uploads')

# Ensure base directory exists
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)


def get_user_root(user_id):
    """Get the root directory for a specific user"""
    user_dir = os.path.join(BASE_UPLOAD_DIR, str(user_id))
    os.makedirs(user_dir, exist_ok=True)
    return os.path.abspath(user_dir)


def validate_path(user_root, relative_path):
    """
    Validate and resolve the path to ensure it stays within user's root directory.
    Returns the absolute path if valid, None otherwise.
    """
    # Normalize the relative path to handle '..' and clean up
    normalized_relative = os.path.normpath(relative_path)
    
    # Prevent absolute paths from being passed
    if os.path.isabs(normalized_relative):
        return None
    
    # Use safe_join which handles path traversal attempts
    try:
        full_path = safe_join(user_root, normalized_relative)
    except:
        return None
    
    if full_path is None:
        return None
    
    # Resolve to absolute path and canonicalize
    full_path = os.path.abspath(full_path)
    user_root_abs = os.path.abspath(user_root)
    
    # Ensure the resolved path is within the user's root directory
    if not full_path.startswith(user_root_abs + os.sep) and full_path != user_root_abs:
        return None
    
    return full_path


@app.route('/api/list', methods=['GET'])
def list_directory():
    """List contents of a directory"""
    user_id = request.args.get('user_id')
    relative_path = request.args.get('path', '')
    
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400
    
    user_root = get_user_root(user_id)
    full_path = validate_path(user_root, relative_path)
    
    if full_path is None:
        return jsonify({'error': 'Invalid path'}), 400
    
    if not os.path.exists(full_path):
        return jsonify({'error': 'Path does not exist'}), 404
    
    if not os.path.isdir(full_path):
        return jsonify({'error': 'Path is not a directory'}), 400
    
    try:
        entries = []
        for entry in os.listdir(full_path):
            entry_path = os.path.join(full_path, entry)
            entry_info = {
                'name': entry,
                'type': 'directory' if os.path.isdir(entry_path) else 'file',
                'size': os.path.getsize(entry_path) if os.path.isfile(entry_path) else None
            }
            entries.append(entry_info)
        
        return jsonify({
            'path': relative_path,
            'entries': entries
        })
    except Exception as e:
        return jsonify({'error': 'Failed to list directory'}), 500


@app.route('/api/download', methods=['GET'])
def download_file():
    """Download a file"""
    user_id = request.args.get('user_id')
    relative_path = request.args.get('path')
    
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400
    
    if not relative_path:
        return jsonify({'error': 'path is required'}), 400
    
    user_root = get_user_root(user_id)
    full_path = validate_path(user_root, relative_path)
    
    if full_path is None:
        return jsonify({'error': 'Invalid path'}), 400
    
    if not os.path.exists(full_path):
        return jsonify({'error': 'File does not exist'}), 404
    
    if not os.path.isfile(full_path):
        return jsonify({'error': 'Path is not a file'}), 400
    
    try:
        return send_file(full_path, as_attachment=True, download_name=os.path.basename(full_path))
    except Exception as e:
        return jsonify({'error': 'Failed to download file'}), 500


@app.route('/api/fileinfo', methods=['GET'])
def get_file_info():
    """Get information about a file"""
    user_id = request.args.get('user_id')
    relative_path = request.args.get('path')
    
    if not user_id:
        return jsonify({'error': 'user_id is required'}), 400
    
    if not relative_path:
        return jsonify({'error': 'path is required'}), 400
    
    user_root = get_user_root(user_id)
    full_path = validate_path(user_root, relative_path)
    
    if full_path is None:
        return jsonify({'error': 'Invalid path'}), 400
    
    if not os.path.exists(full_path):
        return jsonify({'error': 'File does not exist'}), 404
    
    try:
        stat_info = os.stat(full_path)
        mime_type, _ = mimetypes.guess_type(full_path)
        
        file_info = {
            'name': os.path.basename(full_path),
            'path': relative_path,
            'type': 'directory' if os.path.isdir(full_path) else 'file',
            'size': stat_info.st_size,
            'created': stat_info.st_ctime,
            'modified': stat_info.st_mtime,
            'mime_type': mime_type
        }
        
        return jsonify(file_info)
    except Exception as e:
        return jsonify({'error': 'Failed to get file info'}), 500


if __name__ == '__main__':
    app.run(debug=False)